import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct PlantIntent: AppIntent {
    static var title: LocalizedStringResource = "Plant"
    @Parameter(title: "Plant Name") var plantName: String
}

struct PlantWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "PlantWidget",
            intent: PlantIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.plantName) {
                    content.add(model)
                }
            }
        }
    }
}

